/**
 * /api/scan.js
 * - 스킬판독: gemini-2.5-flash-lite (단순 텍스트 OCR)
 * - 사진일괄: gemini-2.5-flash (카드 비전 판정, 고성능 필요)
 */

/* ── Few-shot 예시 이미지 (카드종류 판정 참조용) ── */
const FEW_SHOT_SIG = ""; /* 시그니처: Sig 필기체 텍스트 */
const FEW_SHOT_GG_BG = ""; /* 골든글러브 ① 황금 배경 (이름 주변) */
const FEW_SHOT_GG_LOGO = ""; /* 골든글러브 ② 황금 야구공/글러브 로고 */
const FEW_SHOT_LIVE = ""; /* 라이브: LIVE V1/V2/V3 배지 */

async function callGemini(apiKey, model, contents, maxTokens) {
  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents,
        generationConfig: {
          maxOutputTokens: maxTokens || 8192,
          temperature: 0,
          responseMimeType: 'application/json',
        }
      })
    }
  );
  return res;
}

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const GEMINI_API_KEY = process.env.GEMINI_API_KEY;
  const supabaseUrl = process.env.VITE_SUPABASE_URL;
  const supabaseKey = process.env.VITE_SUPABASE_ANON_KEY;

  if (!GEMINI_API_KEY) {
    return res.status(500).json({ error: 'GEMINI_API_KEY 환경변수가 설정되지 않았습니다.' });
  }

  const { base64, mediaType, prompt, userId, type } = req.body || {};
  const isSkill = type === 'skill';

  /* 타입별 설정 */
  const DAILY_LIMIT      = isSkill ? 10000 : 1000;
  const USER_DAILY_LIMIT = isSkill ? 50    : 10;
  const MODELS_TO_USE    = isSkill
    ? ['gemini-2.5-flash-lite']   /* 스킬판독: 텍스트 OCR */
    : ['gemini-2.5-flash'];       /* 사진일괄: 비전 판정 */
  const today = new Date().toISOString().slice(0, 10);

  /* ── 일일 한도 체크 ── */
  if (supabaseUrl && supabaseKey) {
    try {
      const globalRes = await fetch(
        `${supabaseUrl}/rest/v1/scan_usage?date=eq.${today}`,
        { headers: { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` } }
      );
      const globalData = await globalRes.json();
      const globalCount = (Array.isArray(globalData) && globalData[0]) ? globalData[0].count : 0;
      if (globalCount >= DAILY_LIMIT) {
        return res.status(429).json({ error: `오늘 서비스 전체 한도(${DAILY_LIMIT}회)를 초과했습니다.` });
      }
      if (userId) {
        const userRes = await fetch(
          `${supabaseUrl}/rest/v1/scan_usage_user?date=eq.${today}&user_id=eq.${userId}`,
          { headers: { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` } }
        );
        const userData = await userRes.json();
        const userCount = (Array.isArray(userData) && userData[0]) ? userData[0].count : 0;
        if (userCount >= USER_DAILY_LIMIT) {
          return res.status(429).json({ error: `오늘 사용 한도(${USER_DAILY_LIMIT}회)를 초과했습니다.` });
        }
      }
    } catch (e) {
      console.error('사용량 체크 오류:', e);
    }
  }

  if (!base64 || !prompt) {
    return res.status(400).json({ error: 'base64와 prompt가 필요합니다.' });
  }

  /* 스킬판독: 단일 턴. 사진일괄: 4개 샘플 멀티턴으로 선삽입 */
  const contents = isSkill ? [
    {
      role: 'user',
      parts: [
        { text: prompt },
        { inlineData: { mimeType: mediaType || 'image/jpeg', data: base64 } },
      ]
    }
  ] : [
    /* ── 샘플 1: 시그니처 ── */
    {
      role: 'user',
      parts: [
        { text: '[카드 종류 판별 학습 - 샘플 1]\n아래 이미지는 "시그니처" 카드의 핵심 판별 단서입니다.\n특징: 선수 이름 근처에 빨간색/분홍색 필기체 영문 "Sig"(Signature의 일부) 텍스트가 보입니다.\n→ 이 필기체 "Sig" 텍스트가 보이면 그 카드는 시그니처입니다.' },
        { inlineData: { mimeType: 'image/jpeg', data: FEW_SHOT_SIG } },
      ]
    },
    {
      role: 'model',
      parts: [{ text: '확인했습니다. 빨간/분홍 필기체 "Sig" 텍스트 = 시그니처 카드의 판별 단서.' }]
    },

    /* ── 샘플 2: 골든글러브 (황금 배경) ── */
    {
      role: 'user',
      parts: [
        { text: '[카드 종류 판별 학습 - 샘플 2]\n아래 이미지는 "골든글러브" 카드의 핵심 판별 단서 ①입니다.\n특징: 선수 이름 주변이 노랑/황금색 배경으로 둘러싸여 있습니다.\n→ 이름 주변에 이런 노랑/황금 배경이 있으면 그 카드는 골든글러브입니다.' },
        { inlineData: { mimeType: 'image/jpeg', data: FEW_SHOT_GG_BG } },
      ]
    },
    {
      role: 'model',
      parts: [{ text: '확인했습니다. 이름 주변의 노랑/황금 배경 = 골든글러브 판별 단서 ①.' }]
    },

    /* ── 샘플 3: 골든글러브 (황금 로고) ── */
    {
      role: 'user',
      parts: [
        { text: '[카드 종류 판별 학습 - 샘플 3]\n아래 이미지는 "골든글러브" 카드의 핵심 판별 단서 ②입니다.\n특징: 카드 안쪽에 황금색 야구 글러브와 공이 합쳐진 로고가 있습니다.\n→ 이 황금 글러브+공 로고가 보이면 그 카드는 골든글러브입니다.\n※ 단서 ① 배경 또는 ② 로고 중 하나라도 보이면 골든글러브로 판정.' },
        { inlineData: { mimeType: 'image/jpeg', data: FEW_SHOT_GG_LOGO } },
      ]
    },
    {
      role: 'model',
      parts: [{ text: '확인했습니다. 황금 글러브+공 로고 = 골든글러브 판별 단서 ②. 단서 ① 또는 ② 중 하나라도 있으면 골든글러브.' }]
    },

    /* ── 샘플 4: 라이브 ── */
    {
      role: 'user',
      parts: [
        { text: '[카드 종류 판별 학습 - 샘플 4]\n아래 이미지는 "라이브" 카드의 핵심 판별 단서입니다.\n특징: 사각 배지 안에 흰 글씨로 "LIVE V1" 텍스트가 있습니다.\n(배지 색상은 버전마다 다름: V1=초록 배지, V2=파랑 배지, V3=붉은색 계열 배지. 색상과 무관하게 "LIVE V1/V2/V3" 텍스트 자체가 판별 기준.)\n→ 이 "LIVE V1/V2/V3" 텍스트 배지가 카드에 보이면 라이브 카드입니다.\n→ 검출한 버전("LIVE V1", "LIVE V2", "LIVE V3")은 반드시 그대로 기록해야 합니다.' },
        { inlineData: { mimeType: 'image/jpeg', data: FEW_SHOT_LIVE } },
      ]
    },
    {
      role: 'model',
      parts: [{ text: '확인했습니다. "LIVE V1/V2/V3" 텍스트 배지 = 라이브 카드 판별 기준. 배지 색상(V1 초록 / V2 파랑 / V3 붉은색)은 버전마다 다르지만 색상과 무관하게 텍스트 자체로 판정하며, 검출한 버전 표기는 그대로 기록합니다.' }]
    },

    /* ── 실제 스캔 대상 ── */
    {
      role: 'user',
      parts: [
        { text: prompt },
        { inlineData: { mimeType: mediaType || 'image/jpeg', data: base64 } },
      ]
    }
  ];

  /* ── 모델 순서대로 시도 ── */
  let lastError = '';
  for (const model of MODELS_TO_USE) {
    for (let attempt = 0; attempt < 2; attempt++) {
      try {
        /* 사진일괄: 9명+투수 JSON이 길어서 충분한 토큰 필요 */
        const maxTok = isSkill ? 4096 : 16384;
        const geminiRes = await callGemini(GEMINI_API_KEY, model, contents, maxTok);

        if (geminiRes.status === 503) {
          lastError = `${model} 503`;
          if (attempt === 0) { await new Promise(r => setTimeout(r, 2000)); continue; }
          break;
        }
        if (geminiRes.status === 429) { lastError = `${model} 429`; break; }
        if (geminiRes.status === 404) { lastError = `${model} 404`; break; }

        if (!geminiRes.ok) {
          const errText = await geminiRes.text();
          lastError = `${model} ${geminiRes.status}: ${errText.slice(0, 200)}`;
          break;
        }

        /* ── 성공 ── */
        const geminiData = await geminiRes.json();

        /* 응답 텍스트 추출 (thinking 모델 대응) */
        const parts = geminiData?.candidates?.[0]?.content?.parts || [];
        let text = '';
        for (const part of parts) {
          if (part.text && !part.thought) { text = part.text; break; }
        }
        if (!text) text = parts[parts.length - 1]?.text || '';

        /* 마크다운 코드블록 제거 */
        text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

        /* JSON 배열/객체만 추출 */
        const arrStart = text.indexOf('[');
        const objStart = text.indexOf('{');
        const start = arrStart !== -1 && (objStart === -1 || arrStart < objStart) ? arrStart : objStart;
        const end = start === arrStart ? text.lastIndexOf(']') : text.lastIndexOf('}');
        if (start !== -1 && end !== -1 && end > start) {
          text = text.slice(start, end + 1);
        }

        /* 사용량 업데이트 */
        if (supabaseUrl && supabaseKey) {
          try {
            await fetch(`${supabaseUrl}/rest/v1/scan_usage`, {
              method: 'POST',
              headers: {
                apikey: supabaseKey,
                Authorization: `Bearer ${supabaseKey}`,
                'Content-Type': 'application/json',
                Prefer: 'resolution=merge-duplicates',
              },
              body: JSON.stringify({ date: today, count: 1 }),
            });
            if (userId) {
              const uRes = await fetch(
                `${supabaseUrl}/rest/v1/scan_usage_user?date=eq.${today}&user_id=eq.${userId}`,
                { headers: { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` } }
              );
              const uData = await uRes.json();
              const prev = (Array.isArray(uData) && uData[0]) ? uData[0].count : 0;
              await fetch(`${supabaseUrl}/rest/v1/scan_usage_user`, {
                method: 'POST',
                headers: {
                  apikey: supabaseKey,
                  Authorization: `Bearer ${supabaseKey}`,
                  'Content-Type': 'application/json',
                  Prefer: 'resolution=merge-duplicates',
                },
                body: JSON.stringify({ user_id: userId, date: today, count: prev + 1 }),
              });
            }
          } catch (e) {
            console.error('사용량 업데이트 오류:', e);
          }
        }

        console.log(`성공: ${model}`);
        return res.status(200).json({ text });

      } catch (err) {
        lastError = `${model} 예외: ${err.message}`;
        break;
      }
    }
  }

  return res.status(503).json({
    error: `모든 모델 응답 실패. 잠시 후 다시 시도해주세요. (${lastError})`
  });
}
